# MSIX Detection script for $NaptAppName $NaptVersion
# Generated by NAPT (Not a Package Tool)
# Checks installed AppX packages for the expected identity and version.
# Supports exact version match or minimum version (installed >= expected).
# Exits with code 0 if detected, code 1 if not detected.

param(
    [string]$PackageIdentityName = "$NaptPackageIdentityName",
    [string]$ExpectedVersion = "$NaptVersion",
    [bool]$ExactMatch = $NaptExactMatch
)

# <include _shared_functions.ps1>

$NaptMsixSharedHelper

# Version comparison function
function Compare-Version {
    param(
        [string]$InstalledVersion,
        [string]$ExpectedVersion,
        [bool]$ExactMatch
    )

    if ($ExactMatch) {
        return $InstalledVersion -eq $ExpectedVersion
    }

    # Minimum version comparison (installed >= expected)
    $InstalledParts = $InstalledVersion -split '[.\-]' | ForEach-Object { [int]$_ }
    $ExpectedParts = $ExpectedVersion -split '[.\-]' | ForEach-Object { [int]$_ }

    $MaxLength = [Math]::Max($InstalledParts.Count, $ExpectedParts.Count)

    for ($i = 0; $i -lt $MaxLength; $i++) {
        $InstalledPart = if ($i -lt $InstalledParts.Count) { $InstalledParts[$i] } else { 0 }
        $ExpectedPart = if ($i -lt $ExpectedParts.Count) { $ExpectedParts[$i] } else { 0 }

        if ($InstalledPart -gt $ExpectedPart) {
            return $true
        }
        if ($InstalledPart -lt $ExpectedPart) {
            return $false
        }
    }

    return $true  # Versions are equal
}

# Main detection logic
Initialize-LogFile

# Build component identifier from app name and version (sanitized for valid identifier)
$SanitizedAppName = "$NaptAppName" -replace '[^a-zA-Z0-9]', '-' -replace '-+', '-' -replace '^-|-$', ''
$script:ComponentName = "$SanitizedAppName-$ExpectedVersion-Detection"

Write-CMTraceLog -Message "[Initialization] Detection script running as user: $($script:CurrentIdentity.Name)" -Type "INFO"
Write-CMTraceLog -Message "[Initialization] Starting MSIX detection check for: $NaptAppName (Identity: $PackageIdentityName, Expected: $ExpectedVersion, Mode: $(if ($ExactMatch) { 'Exact Match' } else { 'Minimum Version' }))" -Type "INFO"

$Package = Get-InstalledAppxPackage -PackageIdentityName $PackageIdentityName

if ($Package) {
    $InstalledVersion = $Package.Version

    Write-CMTraceLog -Message "[Detection] Match found: $($Package.Name) (Found: $InstalledVersion, Arch: $($Package.Architecture))" -Type "INFO"

    if ($InstalledVersion) {
        if (Compare-Version -InstalledVersion $InstalledVersion -ExpectedVersion $ExpectedVersion -ExactMatch $ExactMatch) {
            Write-CMTraceLog -Message "[Detection] Version check passed: $InstalledVersion $(if ($ExactMatch) { '=' } else { '>=' }) $ExpectedVersion" -Type "INFO"
            Write-CMTraceLog -Message "[Result] Detected: $NaptAppName (Found: $InstalledVersion, Expected: $(if ($ExactMatch) { '=' } else { '>=' }) $ExpectedVersion, Mode: $(if ($ExactMatch) { 'Exact' } else { 'Minimum' }))" -Type "INFO"
            Write-Output "Installed"
            exit 0
        } else {
            Write-CMTraceLog -Message "[Detection] Version check not met: $InstalledVersion $(if ($ExactMatch) { '!=' } else { '<' }) $ExpectedVersion" -Type "INFO"
        }
    } else {
        Write-CMTraceLog -Message "[Detection] No version found for package: $($Package.Name)" -Type "WARNING"
    }
}

$FoundVersion = if ($Package) { $Package.Version } else { "None" }
Write-CMTraceLog -Message "[Result] Not Detected: $NaptAppName (Found: $FoundVersion, Expected: $(if ($ExactMatch) { '=' } else { '>=' }) $ExpectedVersion, Mode: $(if ($ExactMatch) { 'Exact' } else { 'Minimum' }))" -Type "WARNING"
exit 1
